use std::ffi::{CStr, CString};
use std::os::raw::{c_char, c_int, c_double};

// Declare C functions
extern "C" {
    fn strlen(s: *const c_char) -> usize;
    fn abs(n: c_int) -> c_int;
    fn sqrt(n: c_double) -> c_double;
}

fn safe_strlen(s: &str) -> usize {
    let c_str = CString::new(s).expect("String contains null byte");
    unsafe { strlen(c_str.as_ptr()) }
}

fn main() {
    // strlen
    let len = safe_strlen("Hello, FFI!");
    println!("strlen: {}", len);

    // abs
    let result = unsafe { abs(-42) };
    println!("abs(-42) = {}", result);

    // sqrt
    let root = unsafe { sqrt(144.0) };
    println!("sqrt(144) = {}", root);
}

use std::os::raw::c_int;

// Ensure same memory layout as C
#[repr(C)]
struct Point {
    x: c_int,
    y: c_int,
}

#[repr(C)]
struct Rect {
    origin: Point,
    size: Point,
}

// Expose Rust function to C
#[no_mangle]
pub extern "C" fn rect_area(rect: &Rect) -> c_int {
    rect.size.x * rect.size.y
}

fn main() {
    let rect = Rect {
        origin: Point { x: 0, y: 0 },
        size: Point { x: 10, y: 20 },
    };
    println!("Area: {}", rect_area(&rect));
}

use std::ffi::{CStr, CString};
use std::os::raw::c_char;

// Simulating receiving a C string from foreign code
fn receive_c_string(ptr: *const c_char) -> Option<String> {
    if ptr.is_null() {
        return None;
    }
    unsafe {
        let c_str = CStr::from_ptr(ptr);
        Some(c_str.to_string_lossy().into_owned())
    }
}

// Passing a Rust string to C
fn send_to_c(s: &str) -> *const c_char {
    let c_string = CString::new(s).expect("null byte in string");
    // IMPORTANT: caller must not use this pointer after c_string is dropped!
    // In real code, you'd need to manage the CString's lifetime carefully.
    c_string.into_raw()  // Transfers ownership to C
}

// C must call this to free the string when done
#[no_mangle]
pub unsafe extern "C" fn free_rust_string(ptr: *mut c_char) {
    if !ptr.is_null() {
        let _ = CString::from_raw(ptr);
        // CString is dropped here, freeing the memory
    }
}

fn main() {
    let greeting = "Hello from Rust!";
    let c_ptr = send_to_c(greeting);

    // Simulate receiving it back
    let received = receive_c_string(c_ptr);
    println!("Received: {:?}", received);

    // Free the memory
    unsafe { free_rust_string(c_ptr as *mut c_char); }
}
